import java.util.HashMap;
import java.util.Map;

public class Solution {

    private static char getMirrorChar(char c) {
        if (c >= 'a' && c <= 'z') {
            // Letter mirror: a <-> z, b <-> y, etc.
            return (char) ('a' + ('z' - c));
        } else if (c >= '0' && c <= '9') {
            // Digit mirror: 0 <-> 9, 1 <-> 8, etc.
            return (char) ('0' + ('9' - (c - '0')));
        }
        // Should not happen based on problem constraints
        return c; 
    }

    public static long solve(String s) {
        // 1. Frequency Counting
        Map<Character, Integer> freq = new HashMap<>();
        for (char c : s.toCharArray()) {
            freq.put(c, freq.getOrDefault(c, 0) + 1);
        }

        long totalSum = 0;

        // 2. Iterate over unique characters present in s
        for (char c : freq.keySet()) {
            char m = getMirrorChar(c);

            // Determine if the pair {c, m} has already been counted via m.
            // If m is present in s AND m is lexicographically smaller than c, 
            // then the pair was already counted when we processed m.
            boolean alreadyCounted = freq.containsKey(m) && m < c;

            if (alreadyCounted) {
                continue;
            }

            // Otherwise, calculate the contribution for the pair {c, m}

            // freq(c) is guaranteed to be > 0 since c is in freq.keySet()
            long fc = freq.get(c);

            // freq(m) might be 0 if m is not in s
            long fm = freq.getOrDefault(m, 0);

            // Calculate absolute difference and add to sum
            totalSum += Math.abs(fc - fm);
        }

        return totalSum;
    }
}

