    private static char getMirror(char c) {
        if (c >= 'a' && c <= 'z') {
            // Letter: 'a' (index 0) mirrors 'z' (index 25). Sum of indices is 25.
            return (char) ('a' + ('z' - c));
        } else if (c >= '0' && c <= '9') {
