            return (char) ('0' + ('9' - (c - '0')));
        }
        // Should not happen based on problem constraints
        return c; 
    }

    /**
     * Solves the problem by summing the absolute differences in frequencies 
     * between characters and their mirror characters, considering each pair once.
     * 
     * @param s The input string.
     * @return The sum of absolute differences.
     */
    public static long solve(String s) {
        // Step 1: Frequency Counting
        Map<Character, Integer> frequencies = new HashMap<>();
        for (char c : s.toCharArray()) {
            frequencies.put(c, frequencies.getOrDefault(c, 0) + 1);
        }

