    public static long solve(String s) {
        // Step 1: Calculate frequencies
        Map<Character, Integer> freqMap = new HashMap<>();
        for (char c : s.toCharArray()) {
            freqMap.put(c, freqMap.getOrDefault(c, 0) + 1);
        }

        Set<Character> uniqueChars = freqMap.keySet();
        long totalDifference = 0;

        // Step 2: Iterate over unique characters and calculate differences
        for (char c : uniqueChars) {
            char m = getMirror(c);

            // Since c != m always, we only need to handle ordering to count pairs once.

            if (c < m) {
                // Case 1: c is lexicographically smaller than its mirror m. 
                // This guarantees we count the pair {c, m} when processing c.

                int freqC = freqMap.get(c);
                // m might not be in s, so its frequency is 0
                int freqM = freqMap.getOrDefault(m, 0);

                totalDifference += Math.abs(freqC - freqM);

            } else if (c > m) {
                // Case 2: c is lexicographically larger than its mirror m.

                if (!uniqueChars.contains(m)) {
                    // Subcase 2a: m is not in s. We must count this pair now.
                    // This handles cases like (9, 0) where '9' is in s but '0' is not.
                    int freqC = freqMap.get(c);
                    int freqM = 0; // m is not in s
